# Find all Claude API calls slower than 10 seconds
{ span.gen_ai.system = "anthropic" && duration > 10s }

# Find all rate-limit errors in the last hour
{ span.gen_ai.system = "anthropic" && span.error.type = "rate_limit_error" }

# Find traces where a specific model used more than 2000 output tokens
{ span.gen_ai.request.model = "claude-sonnet-5" && span.gen_ai.usage.output_tokens > 2000 }

# Find all retry attempts (attempt > 1)
{ name = "claude.messages.create attempt" && span.claude.attempt > 1 }

# Find all streaming calls with more than 100 chunks
{ name = "claude.messages.stream" && span.chunk_count > 100 }
